using NP std;
NP phigrOS
{
    il ll read()
    {
        ll x=0,f=1;char ch=gc();
        wh(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
        wh(ch>='0'&&ch<='9'){x=x*10+ch-'0';ch=gc();}
        return x*f;
    }
    void write(ll x)
    {
        if(x<0)pc('-'),x=-x;
        if(x>9)write(x/10);
        pc(x%10+'0');
    }
    void writeln(ll x)
    {
        write(x);
        puts("");
        return;
    }
}
using NP phigrOS;
CI MAXN=2e3+5;
struct so
{
	int x,y,r;
}a[MAXN];
int n,xt,yt,sn,dis[MAXN][MAXN];
bool vis[MAXN];
void dfs(int num,double tu,double sum)
{
	if(a[num].x==xt&&a[num].y==yt)
	{
		write((int)sum);
		return;
	}
	FOR(i,1,n)
	{
		if(!vis[i]&&dis[num][i]==pow(a[num].r+a[i].r,2))
		{
			double tmp=tu*a[num].r/a[i].r;
			vis[i]=true;
			dfs(i,tmp,sum+tmp);
			vis[i]=false;
		}
	}
}
signed main(void)
{
	n=read(),xt=read(),yt=read();
	FOR(i,1,n)
	{
		a[i].x=read(),a[i].y=read(),a[i].r=read();
		if(a[i].x==0&&a[i].y==0)
		{
			sn=i;
		}
	}
	FOR(i,1,n-1)
	{
		FOR(j,i+1,n)
		{
			dis[i][j]=dis[j][i]=pow((a[i].x-a[j].x),2)+pow((a[i].y-a[j].y),2);
		}
	}
	vis[sn]=1;
	dfs(sn,1e4,1e4);
	return false;
}
